package concrete.goonie.chart.api.data; import concrete.goonie.chart.api.data.render.RectDataSetRenderer; import concrete.goonie.chart.api.model.Timeframe; import concrete.goonie.chart.internal.render.*; public final class RectDataSet extends DataSet { private final double[] xValues,yValues,x2Values,y2Values; private final String[] labels; private final RectDataSetRenderer renderer = new RectDataSetRenderer(); private Style rectStyle = new Style(0x223B82F6,1.5f,true).withCornerRadius(8f); private Style borderStyle = new Style(0xCC60A5FA,1.2f,false).withCornerRadius(8f); public RectDataSet(String name, double[] xValues, double[] yValues, double[] x2Values, double[] y2Values, String[] labels, Timeframe... timeframes){ super(name,DataSetType.RECT,timeframes); this.xValues=xValues; this.yValues=yValues; this.x2Values=x2Values; this.y2Values=y2Values; this.labels=labels==null?new String[xValues.length]:labels; } public int sizeValue(){ return xValues.length; } public double xValue(int i){ return xValues[i]; } public double yValue(int i){ return yValues[i]; } public double x2Value(int i){ return x2Values[i]; } public double y2Value(int i){ return y2Values[i]; } public String label(int i){ return labels.length>i?labels[i]:""; } public Style getRectStyle(){ return rectStyle; } public void setRectStyle(Style rectStyle){ this.rectStyle=rectStyle; } public Style getBorderStyle(){ return borderStyle; } public void setBorderStyle(Style borderStyle){ this.borderStyle=borderStyle; } @Override public void render(RenderList out, Transform t, int visibleFrom, int visibleTo){ renderer.render(this,out,t,visibleFrom,visibleTo); } }